 .author-tag {
   position: absolute;
   bottom: 48px;
   left: 72px;
   font-size: 14px;
   font-weight: 500;
   color: var(--text-muted);
 }

 /* ── Typography ── */
 .slide-label {
   font-size: 14px;
   font-weight: 700;
   letter-spacing: 3px;
   text-transform: uppercase;
   color: var(--accent-blue);
   margin-bottom: 24px;
 }

 .slide-title {
   font-size: 52px;
   font-weight: 800;
   line-height: 1.15;
   margin-bottom: 32px;
   letter-spacing: -1px;
 }

 .slide-subtitle {
   font-size: 24px;
   font-weight: 500;
   line-height: 1.5;
   color: var(--text-secondary);
   margin-bottom: 40px;
 }

 .highlight { color: var(--accent-blue); }
 .highlight-green { color: var(--accent-green); }
 .highlight-amber { color: var(--accent-amber); }
 .highlight-red { color: var(--accent-red); }
 .highlight-cyan { color: var(--accent-cyan); }
 .highlight-purple { color: var(--accent-purple); }

 /* ── Cards & Containers ── */
 .card {
   background: var(--bg-card);
   border: 1px solid var(--border);
   border-radius: 16px;
   padding: 32px;
   margin-bottom: 20px;
 }

 .card-header {
   font-size: 14px;
   font-weight: 700;
   letter-spacing: 2px;
   text-transform: uppercase;
   color: var(--text-muted);
   margin-bottom: 16px;
 }

 /* ── Table styles ── */
 .comparison-table {
   width: 100%;
   border-collapse: separate;
   border-spacing: 0;
   border-radius: 16px;
   overflow: hidden;
   margin-bottom: 24px;
 }

 .comparison-table th {
   background: var(--bg-card-alt);
   padding: 20px 24px;
   text-align: left;
   font-size: 14px;
   font-weight: 700;
   letter-spacing: 1.5px;
   text-transform: uppercase;
   color: var(--text-muted);
   border-bottom: 1px solid var(--border);
 }

 .comparison-table td {
   padding: 22px 24px;
   font-size: 20px;
   font-weight: 500;
   background: var(--bg-card);
   border-bottom: 1px solid var(--border);
 }

 .comparison-table tr:last-child td {
   border-bottom: none;
 }
